package controller; import javax.swing.*;import javax.swing.table.*;import model.PlayerCard;import service.*;import service.impl.*;import util.*;
public class PlayerCardFrame extends JFrame{PlayerCardService s=new PlayerCardServiceImpl();DefaultTableModel m=new DefaultTableModel(new String[]{"ID","卡名","球員","運動","隊伍","年份","品牌","級別","價格","庫存"},0);JTable table=new JTable(m);JTextField id=new JTextField(),cn=new JTextField(),pn=new JTextField(),sport=new JTextField(),team=new JTextField(),year=new JTextField(),brand=new JTextField(),grade=new JTextField(),price=new JTextField(),qty=new JTextField(),kw=new JTextField(); public PlayerCardFrame(){setTitle("球員卡市場");UiStyle.frame(this);add(UiStyle.label("🃏 球員卡市場 CRUD",30,20,380,40,26));kw.setBounds(350,30,240,32);add(kw);JButton search=UiStyle.btn("搜尋",600,30,90,32);add(search);JScrollPane sp=new JScrollPane(table);sp.setBounds(30,80,640,430);add(sp);String[] labs={"ID","卡名","球員","運動","隊伍","年份","品牌","級別","價格","庫存"};JTextField[] fs={id,cn,pn,sport,team,year,brand,grade,price,qty};int x=700,y=70;for(int i=0;i<fs.length;i++){add(UiStyle.label(labs[i],x,y,70,25,13));fs[i].setBounds(x+70,y,210,28);add(fs[i]);y+=38;}JButton save=UiStyle.btn("新增/修改",700,470,120,38),del=UiStyle.btn("刪除",835,470,90,38),cart=UiStyle.btn("加入購物車",700,520,225,38);add(save);add(del);add(cart);table.getSelectionModel().addListSelectionListener(e->pick());save.addActionListener(e->save());del.addActionListener(e->del());search.addActionListener(e->load(kw.getText()));cart.addActionListener(e->JOptionPane.showMessageDialog(this,"此版已建立 cart_items 資料表，可於購物車頁擴充加入資料。"));load("");}
 void load(String k){m.setRowCount(0);for(PlayerCard x:s.search(k))m.addRow(x.row());}
 void pick(){int r=table.getSelectedRow();if(r<0)return;JTextField[] fs={id,cn,pn,sport,team,year,brand,grade,price,qty};for(int i=0;i<fs.length;i++)fs[i].setText(m.getValueAt(r,i)+"");}
 void save(){PlayerCard c=new PlayerCard();c.id=id.getText().isBlank()?0:Integer.parseInt(id.getText());c.cardName=cn.getText();c.playerName=pn.getText();c.sport=sport.getText();c.team=team.getText();c.cardYear=Integer.parseInt(year.getText().isBlank()?"0":year.getText());c.brand=brand.getText();c.grade=grade.getText();c.price=Double.parseDouble(price.getText().isBlank()?"0":price.getText());c.quantity=Integer.parseInt(qty.getText().isBlank()?"0":qty.getText());c.cardNumber="";c.description="";c.imagePath="";s.save(c);load(kw.getText());}
 void del(){if(!id.getText().isBlank()){s.delete(Integer.parseInt(id.getText()));load(kw.getText());}}
}
